import React, { useState, useEffect } from 'react';

function App() {
    const [projects, setProjects] = useState([]);
    const [error, setError] = useState(null);

    useEffect(() => {
        // Wir fragen das Backend auf Port 8081 ab
        fetch('http://localhost:8081/api/projects', {
            headers: {
                // Login-Daten aus deiner data.sql (danny : password)
                'Authorization': 'Basic ' + btoa('danny:password')
            }
        })
        .then(res => {
            if (!res.ok) throw new Error('Login fehlgeschlagen oder Server offline');
            return res.json();
        })
        .then(data => setProjects(data))
        .catch(err => setError(err.message));
    }, []);

    return (
        <div style={{ padding: '40px', fontFamily: 'sans-serif' }}>
        <h1 style={{ color: '#2c3e50' }}>IT-Service Task Manager</h1>
        <hr />
        {error ? (
            <p style={{ color: 'red' }}>⚠️ {error}</p>
        ) : (
            <div>
            <h3>Aktive Projekte aus der Datenbank:</h3>
            <ul>
            {projects.map(p => (
                <li key={p.id}>
                <strong>{p.name}</strong>: {p.description} (Status: {p.status})
                </li>
            ))}
            </ul>
            </div>
        )}
        </div>
    );
}

export default App;
